1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	export function nextGeneration(cells: Cell[]): Cell[] {
10	  const isAlive = (x: number, y: number): boolean =>
11	    cells.some(([cx, cy]) => cx === x && cy === y);
12	
13	  const countNeighbors = (x: number, y: number): number =>
14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
15	
16	  return cells.filter(([x, y]) => {
17	    const n = countNeighbors(x, y);
18	    return n === 2 || n === 3;
19	  });
20	}
