1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with 0 neighbors — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells each with 1 neighbor die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 Survival: live cell with 2 live neighbors survives — L-shape (0,0) survives with neighbors (1,0),(0,1)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toContainEqual([0, 0]);
17	  });
18	  it("Rule 3 Overpopulation: live cell with 4 live neighbors dies — plus-shape center (1,1) dies", () => {
19	    const result = nextGeneration([[0, 1], [1, 0], [1, 1], [1, 2], [2, 1]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
